SELECT id, user_id, log_date, calories, protein, fat, carbs, exercise_minutes, created_at, updated_at
FROM sp_daily_logs
WHERE user_id = #{userId} AND log_date = #{logDate}

SELECT id, user_id, log_date, calories, protein, fat, carbs, exercise_minutes, created_at, updated_at
FROM sp_daily_logs
WHERE user_id = #{userId}
  AND log_date BETWEEN #{fromDate} AND #{toDate}
ORDER BY log_date ASC
